import { MakeLogicType, actions, kea, path, reducers } from 'kea'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface newAccountMenuLogicValues {
    isAccountMenuOpen: boolean
    isOrgSwitcherOpen: boolean
    isProjectSwitcherOpen: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface newAccountMenuLogicActions {
    closeOrgSwitcher: () => {
        value: true
    }
    closeProjectSwitcher: () => {
        value: true
    }
    openOrgSwitcher: () => {
        value: true
    }
    openProjectSwitcher: () => {
        value: true
    }
    setAccountMenuOpen: (isOpen: boolean) => {
        isOpen: boolean
    }
    toggleAccountMenu: () => {
        value: true
    }
    toggleOrgSwitcher: () => {
        value: true
    }
    toggleProjectSwitcher: () => {
        value: true
    }
}

export type newAccountMenuLogicType = MakeLogicType<newAccountMenuLogicValues, newAccountMenuLogicActions>

export const newAccountMenuLogic = kea<newAccountMenuLogicType>([
    path(['lib', 'components', 'Account', 'accountMenuLogic']),
    actions({
        setAccountMenuOpen: (isOpen: boolean) => ({ isOpen }),
        toggleAccountMenu: true,
        // Project switcher modal
        openProjectSwitcher: true,
        closeProjectSwitcher: true,
        toggleProjectSwitcher: true,
        // Org switcher modal
        openOrgSwitcher: true,
        closeOrgSwitcher: true,
        toggleOrgSwitcher: true,
    }),
    reducers({
        isAccountMenuOpen: [
            false,
            {
                setAccountMenuOpen: (_, { isOpen }) => isOpen,
                toggleAccountMenu: (state) => !state,
            },
        ],
        isProjectSwitcherOpen: [
            false,
            {
                openProjectSwitcher: () => true,
                closeProjectSwitcher: () => false,
                toggleProjectSwitcher: (state) => !state,
            },
        ],
        isOrgSwitcherOpen: [
            false,
            {
                openOrgSwitcher: () => true,
                closeOrgSwitcher: () => false,
                toggleOrgSwitcher: (state) => !state,
            },
        ],
    }),
])
